//\n//  RadarViewModel.swift\n//  DeviceRadar\n//\n//  Created by DeviceRadar Team.\n//  Copyright © 2026 LethalLethes. All rights reserved.\n//\n\nimport Foundation\nimport Combine\n\n/// ViewModel managing the data collection and UI state for DeviceRadar.\n///\n/// Responsibilities:\n/// - Orchestrate data collection from services\n/// - Manage loading and error states\n/// - Filter signals by permission tier\n/// - Calculate statistics\n/// - Update UI via @Published properties\nclass RadarViewModel: ObservableObject {\n    // MARK: - Published Properties\n    \n    /// All collected signal categories.\n    @Published var categories: [SignalCategory] = []\n    \n    /// Currently selected tier filter (nil = show all).\n    @Published var selectedTier: Tier? = nil\n    \n    /// Whether data collection is in progress.\n    @Published var isLoading = false\n    \n    /// Latest collection timestamp.\n    @Published var generatedAt = \"\"\n    \n    /// Error message if collection fails.\n    @Published var errorMessage: String? = nil\n    \n    // MARK: - Private Properties\n    \n    private let dataCollector: DataCollectorService\n    private let logger = Logger.shared\n    \n    // MARK: - Initialization\n    \n    /// Creates a new RadarViewModel.\n    ///\n    /// - Parameter dataCollector: Service to use for data collection.\n    ///   Defaults to DeviceRadarCollectorService.\n    init(dataCollector: DataCollectorService = DeviceRadarCollectorService()) {\n        self.dataCollector = dataCollector\n        logger.info(\"RadarViewModel initialized\")\n    }\n    \n    // MARK: - Public Methods\n    \n    /// Triggers signal collection from all services.\n    ///\n    /// Executes on background queue to avoid blocking UI.\n    /// Updates @Published properties on main thread.\n    func generate() {\n        guard !isLoading else {\n            logger.debug(\"Collection already in progress, ignoring request\")\n            return\n        }\n        \n        logger.info(\"Starting signal generation\")\n        isLoading = true\n        errorMessage = nil\n        \n        DispatchQueue.global(qos: .userInitiated).async { [weak self] in\n            guard let self = self else { return }\n            \n            do {\n                let collected = self.dataCollector.collectSignals()\n                \n                let formatter = DateFormatter()\n                formatter.dateFormat = \"dd.MM.yyyy · HH:mm:ss\"\n                let timestamp = formatter.string(from: Date())\n                \n                DispatchQueue.main.async {\n                    self.categories = collected\n                    self.generatedAt = timestamp\n                    self.isLoading = false\n                    \n                    let signalCount = collected.flatMap { $0.signals }.count\n                    self.logger.info(\"Signal generation completed: \\(collected.count) categories, \\(signalCount) signals\")\n                }\n            } catch {\n                DispatchQueue.main.async {\n                    self.errorMessage = \"Collection failed: \\(error.localizedDescription)\"\n                    self.isLoading = false\n                    self.logger.error(\"Signal generation failed: \\(error.localizedDescription)\")\n                }\n            }\n        }\n    }\n    \n    // MARK: - Computed Properties\n    \n    /// Returns categories filtered by selected tier.\n    ///\n    /// If no tier is selected, returns all categories.\n    var filtered: [SignalCategory] {\n        guard let tier = selectedTier else {\n            return categories\n        }\n        return categories.filter { $0.tier == tier }\n    }\n    \n    /// Returns the total number of signals for a given tier.\n    ///\n    /// - Parameter tier: The tier to count signals for.\n    /// - Returns: Total number of signals in that tier.\n    func count(for tier: Tier) -> Int {\n        categories\n            .filter { $0.tier == tier }\n            .flatMap { $0.signals }\n            .count\n    }\n    \n    /// Returns the total number of signals across all tiers.\n    var totalSignalCount: Int {\n        categories.flatMap { $0.signals }.count\n    }\n    \n    /// Returns the total number of categories.\n    var totalCategoryCount: Int {\n        categories.count\n    }\n}\n